#include <stdio.h>
#include <math.h>

int main(void){
    int W=2400,H=1800,row,col;
    double asp=4.0/3.0;
    double camy=1.5;
    double Cx=0.0,Cy=1.0,Cz=-5.0,R=1.0;
    double s3=1.0/sqrt(3.0);
    double Lx=s3,Ly=s3,Lz=-s3;
    double amb=0.30,dif=1.2124;
    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    for(row=0;row<H;row++){
        for(col=0;col<W;col++){
            double u=(col+0.5)/W, v=(row+0.5)/H;
            double dx=(2*u-1)*asp, dy=1-2*v, dz=-1.0;
            double nl=sqrt(dx*dx+dy*dy+dz*dz);
            double nx=dx/nl, ny=dy/nl, nz=dz/nl;
            double r,g,b;
            /* sphere */
            double ocx=-Cx, ocy=camy-Cy, ocz=-Cz;
            double bb=ocx*nx+ocy*ny+ocz*nz;
            double cc=ocx*ocx+ocy*ocy+ocz*ocz-R*R;
            double disc=bb*bb-cc;
            double tS=1e30; int hitS=0;
            if(disc>0){ double t=-bb-sqrt(disc); if(t>0){tS=t;hitS=1;} }
            double tP=1e30; int hitP=0;
            if(ny<0){ tP=-camy/ny; hitP=1; }
            if(hitS && tS<tP){
                double hx=tS*nx, hy=camy+tS*ny, hz=tS*nz;
                double sx=(hx-Cx)/R, sy=(hy-Cy)/R, sz=(hz-Cz)/R;
                double ndl=sx*Lx+sy*Ly+sz*Lz; if(ndl<0)ndl=0;
                double fac=amb+dif*ndl;
                r=170*fac; g=33*fac; b=33*fac;
            } else if(hitP){
                double Px=tP*nx, Pz=tP*nz;
                int par=(((int)floor(Px+1e-6))+((int)floor(Pz+1e-6)))&1;
                double alb=par?67.0:152.0;
                double qx=Px-Cx, qy=-Cy, qz=Pz-Cz;
                double bs=qx*Lx+qy*Ly+qz*Lz;
                double cs=qx*qx+qy*qy+qz*qz-R*R;
                double sh=(bs<0 && bs*bs-cs>0)?amb:1.0;
                r=g=b=alb*sh;
            } else {
                double a=0.5*(ny+1);
                r=255*(1-a)+a*127.5;
                g=255*(1-a)+a*178.5;
                b=255;
            }
            int ir=(int)(r+0.5), ig=(int)(g+0.5), ib=(int)(b+0.5);
            if(ir<0)ir=0; if(ir>255)ir=255;
            if(ig<0)ig=0; if(ig>255)ig=255;
            if(ib<0)ib=0; if(ib>255)ib=255;
            fprintf(f,"%d %d %d\n",ir,ig,ib);
        }
    }
    fclose(f);
    return 0;
}

